using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_50bcfa304afd4789b6de8edf491cc098.Auth;

/// <summary>
/// Server-side provider that creates a hardcoded authenticated user and
/// persists the claims via <see cref="PersistentComponentState"/> so the
/// WebAssembly runtime can rehydrate them after the interactive handoff.
/// </summary>
public sealed class ServerAuthenticationStateProvider
    : ServerAuthenticationStateProvider<ServerAuthenticationStateProvider>
{
}

public class ServerAuthenticationStateProvider<T>
    : RevalidatingServerAuthenticationStateProvider where T : ServerAuthenticationStateProvider<T>
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authTask;

    protected override TimeSpan RevalidationInterval => TimeSpan.FromMinutes(30);

    public ServerAuthenticationStateProvider(
        ILoggerFactory loggerFactory,
        PersistentComponentState persistentState)
        : base(loggerFactory)
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        return Task.FromResult(new AuthenticationState(user));
    }

    protected override Task<bool> ValidateAuthenticationStateAsync(
        AuthenticationState authenticationState, CancellationToken cancellationToken)
    {
        return Task.FromResult(true);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authTask ?? GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var claimData = principal.Claims
                .Select(c => new ClaimRecord(c.Type, c.Value))
                .ToArray();

            _persistentState.PersistAsJson(nameof(ClaimRecord), claimData);
        }
    }

    protected override void Dispose(bool disposing)
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
        base.Dispose(disposing);
    }
}

public record ClaimRecord(string Type, string Value);

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_50bcfa304afd4789b6de8edf491cc098.Client.Auth;

/// <summary>
/// Client-side provider that rehydrates the authenticated user from claims
/// persisted by the server via <see cref="PersistentComponentState"/>.
/// </summary>
public sealed class ClientAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authState;

    public ClientAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<ClaimRecord[]>(nameof(ClaimRecord), out var claimData)
            && claimData is { Length: > 0 })
        {
            var claims = claimData.Select(c => new Claim(c.Type, c.Value));
            var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
            var user = new ClaimsPrincipal(identity);
            _authState = Task.FromResult(new AuthenticationState(user));
        }
        else
        {
            _authState = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authState;
}

public record ClaimRecord(string Type, string Value);

@page "/profile"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.AspNetCore.Components.Authorization
@using System.Security.Claims
@attribute [Authorize]
@rendermode InteractiveAuto

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>

        <h3>Roles</h3>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
    <NotAuthorized>
        <p>You are not logged in.</p>
    </NotAuthorized>
</AuthorizeView>

